import React from 'react';
import { StarIcon, StarHalfIcon } from 'lucide-react';

export function StarRating({ rating, maxStars = 5 }) {
  return (
    <div className="flex items-center space-x-0.5" aria-label={`Rating: ${rating} out of ${maxStars} stars`}>
      {[...Array(maxStars)].map((_, i) => {
        const starValue = i + 1;
        if (rating >= starValue) {
          return <StarIcon key={i} className="w-4 h-4 text-amber-400 fill-amber-400" aria-hidden="true" />;
        }

        if (rating >= starValue - 0.5) {
          return <StarHalfIcon key={i} className="w-4 h-4 text-amber-400 fill-amber-400" aria-hidden="true" />;
        }

        return <StarIcon key={i} className="w-4 h-4 text-gray-300" aria-hidden="true" />;
      })}
      <span className="ml-1.5 text-sm font-medium text-gray-700">{rating.toFixed(1)}</span>
    </div>
  );
}
